Resposta:
To import a Word document into **Adobe InDesign** while preserving **text formatting** (fonts, styles, spacing, etc.), you should avoid direct import methods that may strip formatting. Instead, use **InDesign's built-in "Import from Text" feature** with proper settings.

Below is a **script (JavaScript for ExtendScript)** that automates the import of a Word document into InDesign while **preserving text formatting** as much as possible.

---

### ✅ **Script: Import Word Doc to InDesign with Formatting Preservation**

```javascript
// ExtendScript for Adobe InDesign
// Save as: ImportWordWithFormatting.jsx
// Run via File > Scripts > Other Script...

#target "InDesign"

if (app.documents.length > 0) {
    // Get current document
    var doc = app.activeDocument;

    // Prompt user for Word file
    var file = File.openDialog();
    if (!file) {
        alert("No file selected. Script cancelled.");
        exit();
    }

    // Import Word file
    var wdDoc = Indigo(file); // Indigo is InDesign's Word engine
    if (!wdDoc) {
        alert("Failed to open Word document.");
        exit();
    }

    // Import text with formatting
    var story = doc.pages[0].textFrames.addTextFrame(file.name, 1, 0);

    // Use "Import as Plain Text" or better: "Import as Text with Formatting"
    // But we use "Import from Text" with proper settings
    var importOptions = new ImportOptions(file);
    importOptions.format = ImportOptions.Format.WPS; // Best for Word 2007+
    importOptions.preserveFormatting = true;        // Critical: preserves fonts, styles, etc.
    importOptions.fontEmulation = "embed";         // Embed fonts if possible
    importOptions.keepLinking = false;             // Break links to Word

    // Import the content

